def shared_contact(a, b, field):
    return a.get(field) and a.get(field) == b.get(field)

def surname_overlap(a, b):
    sa = set(a.casefold().split())
    sb = set(b.casefold().split())
    return len(sa & sb) / max(1, len(sa | sb))

