def backoff_sleep_ms(attempt, base=100, cap=2000):
    return min(cap, base * (2 ** (attempt - 1)))

def process_with_dlq(items, flaky_ids):
    ok, dlq, ckpt = [], [], set()
    for it in items:
        if it in ckpt:
            continue
        if it in flaky_ids:
            dlq.append(it)
        else:
            ok.append(it); ckpt.add(it)
    return ok, dlq, sorted(ckpt)

