from collections import defaultdict, deque
# grafo no dirigido sintético
adj = defaultdict(set)
for u, v in [("A", "B"), ("B", "C"), ("C", "D"), ("E", "F"), ("B", "D")]:
    adj[u].add(v); adj[v].add(u)

def degree(n):
    return len(adj[n])

def components():
    seen, comps = set(), []
    for start in list(adj):
        if start in seen:
            continue
        q, comp = [start], []
        seen.add(start)
        while q:
            n = q.pop()
            comp.append(n)
            for m in adj[n]:
                if m not in seen:
                    seen.add(m); q.append(m)
        comps.append(sorted(comp))
    return comps

def bfs_path(src, dst, max_depth=5):
    q = deque([(src, [src])])
    seen = {src}
    while q:
        n, path = q.popleft()
        if n == dst:
            return path
        if len(path) > max_depth:
            continue
        for m in sorted(adj[n]):
            if m not in seen:
                seen.add(m)
                q.append((m, path + [m]))
    return None

