for u, v in [("A", "B"), ("B", "C"), ("C", "D")]:
    adj[u].add(v); adj[v].add(u)

def path(s, t, max_h=4):
    q = deque([(s, [s])])
    seen = {s}
    while q:
        n, p = q.popleft()
        if n == t:
            return p
        if len(p) > max_h:
            continue
        for m in sorted(adj[n]):
            if m not in seen:
                seen.add(m)
                q.append((m, p + [m]))
    return None
print("path", path("A", "D"))
print("hops", len(path("A", "D")) - 1)
print("repro", True)

